object ApiHelper {
    private const val SUPABASE_URL = "https://xvldfsmxskhemkslsbym.supabase.co/functions/v1/monitor-builds"
    private const val ANON_KEY = "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6Inh2bGRmc214c2toZW1rc2xzYnltIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NjI2ODgxNzksImV4cCI6MjA3ODI2NDE3OX0.5arqrx8Tt7v-hpXpo_ncoK4IX8th9IibxAuv93SSoOU"

    private val client = OkHttpClient.Builder()
        .connectTimeout(30, TimeUnit.SECONDS)
        .readTimeout(30, TimeUnit.SECONDS)
        .build()

    private val JSON_TYPE = "application/json; charset=utf-8".toMediaType()

    // FETCH ALL RUNS
    fun fetchRuns(repo: String): List<BuildStatus> {
        LogManager.log("API: Fetching runs for $repo")
        val jsonBody = JSONObject().put("action", "fetch_runs").put("repo", repo)
        val request = Request.Builder()
            .url(SUPABASE_URL)
            .addHeader("Authorization", "Bearer $ANON_KEY")
            .post(jsonBody.toString().toRequestBody(JSON_TYPE))
            .build()

        try {
            client.newCall(request).execute().use { response ->
                if (!response.isSuccessful) {
                    LogManager.log("API ERROR: HTTP ${response.code}")
                    return emptyList()
                }
                val body = response.body?.string() ?: return emptyList()
                val json = JSONObject(body)
                if (!json.optBoolean("success")) return emptyList()

                val runsArray = json.optJSONArray("runs") ?: return emptyList()
                val list = mutableListOf<BuildStatus>()

                for (i in 0 until runsArray.length()) {
                    val obj = runsArray.getJSONObject(i)
                    list.add(BuildStatus(
                        runId = obj.optLong("id"),
                        runNumber = obj.optInt("run_number"),
                        name = obj.optString("name"),
                        status = obj.optString("status"),
                        conclusion = obj.optString("conclusion", "unknown"),
                        commitMsg = obj.optString("commit_msg"),
                        branch = obj.optString("branch", "main"),
                        conduitId = if (obj.isNull("conduit_id")) null else obj.optString("conduit_id")
                    ))
                }
                return list
            }
        } catch (e: Exception) {
            LogManager.log("API CRASH: ${e.message}")
            e.printStackTrace()
            return emptyList()
        }
    }

    // NEW FUNCTION: Asks Supabase for the direct download link
