        val jsonBody = JSONObject()
            .put("action", "fetch_artifact_link")
            .put("run_id", runId)
            .put("repo", repo)
            .put("branch", branch)

        val request = Request.Builder()
            .url(SUPABASE_URL)
            .addHeader("Authorization", "Bearer $ANON_KEY")
            .post(jsonBody.toString().toRequestBody(JSON_TYPE))
            .build()

        try {
            client.newCall(request).execute().use { response ->
                val body = response.body?.string() ?: return null
                val json = JSONObject(body)
                if (json.optBoolean("success")) {
                    return json.optString("url")
                }
            }
        } catch (e: Exception) { e.printStackTrace() }
        return null
    }

    // KEEP OLD METHOD FOR SERVICE COMPATIBILITY
    fun fetchBuildStatus(repo: String): BuildStatus? {
        val list = fetchRuns(repo)
        return if (list.isNotEmpty()) list[0] else null
    }
