import { serve } from "https://deno.land/std@0.192.0/http/server.ts"
import { createClient } from "https://esm.sh/@supabase/supabase-js@2.38.4"

const DEFAULT_REPO = "GetyeTek/Notify";
const ARTIFACT_NAME = "notify-app-debug";

serve(async (req) => {
  const corsHeaders = {
    'Access-Control-Allow-Origin': '*',
    'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
  };

  if (req.method === 'OPTIONS') return new Response('ok', { headers: corsHeaders });

  try {
    const gitHubToken = Deno.env.get('GITHUB_PAT');
    const supabaseUrl = Deno.env.get('SUPABASE_URL') ?? "";
    const supabaseKey = Deno.env.get('SUPABASE_SERVICE_ROLE_KEY') ?? "";
    const supabase = createClient(supabaseUrl, supabaseKey);

    if (!gitHubToken) throw new Error("Server Error: GITHUB_PAT not configured in Edge Runtime");

    const bodyText = await req.text();
    if (!bodyText && req.method === 'POST') throw new Error("Empty request body");

    const body = bodyText ? JSON.parse(bodyText) : {};
    const { action, repo, run_id, branch = "main" } = body;
    const targetRepo = repo || DEFAULT_REPO;

    console.log(`[${action}] Targeting: ${targetRepo} on ${branch}`);

    const ghHeaders = {
      "Authorization": `Bearer ${gitHubToken}`,
      "Accept": "application/vnd.github.v3+json",
    };

    // 1. FETCH RUNS WITH HISTORY JOIN
    if (action === 'fetch_runs') {
      const url = `https://api.github.com/repos/${targetRepo}/actions/runs?per_page=20&branch=${branch}`;
      const res = await fetch(url, { headers: ghHeaders });

      if (!res.ok) throw new Error(`GitHub API responded with ${res.status}`);
      const data = await res.json();

      const workflowRuns = data.workflow_runs || [];
      const shas = workflowRuns.map((r: any) => r.head_sha);

      // Join with your 'reliable' history table
      const { data: historyItems } = await supabase
        .from('history')
        .select('sha, conduit_id, title')
        .in('sha', shas);

      const runs = workflowRuns.map((r: any) => {
        const match = historyItems?.find(h => h.sha === r.head_sha);
        return {
            id: r.id,
            run_number: r.run_number,
            name: r.name,
            status: r.status,
            conclusion: r.conclusion || "in_progress",
            commit_msg: match?.title || r.head_commit?.message || "No message",
            branch: r.head_branch,
            conduit_id: match ? match.conduit_id : null,
            github_url: r.html_url
        };
      });

      return new Response(JSON.stringify({ success: true, count: runs.length, runs }), {
        headers: { ...corsHeaders, 'Content-Type': 'application/json' }
      });
    }

    // 2. SMART ARTIFACT LINK (Verification Step)
    if (action === 'fetch_artifact_link') {
        if (run_id) {
            // Verify that this specific run actually has artifacts
            const verifyUrl = `https://api.github.com/repos/${targetRepo}/actions/runs/${run_id}/artifacts`;
            const vRes = await fetch(verifyUrl, { headers: ghHeaders });
            const vData = await vRes.json();

            const hasArtifact = vData.artifacts?.some((a: any) => a.name === ARTIFACT_NAME);
            if (!hasArtifact) {
                console.warn(`No artifact '${ARTIFACT_NAME}' found for run ${run_id}`);
            }
        }

        // Use nightly.link for the proxy download
        const publicUrl = `https://nightly.link/${targetRepo}/workflows/build.yml/${branch}/${ARTIFACT_NAME}.zip`;

        return new Response(JSON.stringify({ 
            success: true, 
            url: publicUrl, 
            info: "Link points to the latest successful build for this branch."
        }), { 
            headers: { ...corsHeaders, 'Content-Type': 'application/json' } 
        });
    }

    return new Response(JSON.stringify({ success: false, error: "Action not implemented" }), { 
        status: 400, 
        headers: corsHeaders 
    });

  } catch (error) {
    console.error("Function Error:", error.message);
    return new Response(JSON.stringify({ success: false, error: error.message }), { 
        status: 500, 
        headers: { ...corsHeaders, 'Content-Type': 'application/json' } 
    });
  }
});

