import com.google.android.material.textfield.TextInputEditText
import android.view.View
import androidx.activity.result.contract.ActivityResultContracts
import android.Manifest
import kotlinx.coroutines.*

class MainActivity : AppCompatActivity() {

    private lateinit var adapter: BuildAdapter
    private val scope = CoroutineScope(Dispatchers.Main)

    private val requestPermissionLauncher = registerForActivityResult(
        ActivityResultContracts.RequestPermission()
    ) { isGranted ->
        if (!isGranted) {
            Toast.makeText(this, "Notifications disabled. You won't see build alerts!", Toast.LENGTH_LONG).show()
        }
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main)

        val fabRefresh = findViewById<View>(R.id.fab_refresh)
        val btnMonitor = findViewById<View>(R.id.btn_monitor)
        val btnKill = findViewById<View>(R.id.btn_kill)
        val btnLogs = findViewById<View>(R.id.btn_logs)
        val statusText = findViewById<TextView>(R.id.text_monitor_status)
        val recycler = findViewById<RecyclerView>(R.id.recycler_builds)
        val inputRepo = findViewById<TextInputEditText>(R.id.input_repo)
        val switchAuto = findViewById<com.google.android.material.switchmaterial.SwitchMaterial>(R.id.switch_auto_update)
        val btnPerm = findViewById<TextView>(R.id.btn_permission_settings)

        // Restore saved prefs
        val prefs = getSharedPreferences("BuildPrefs", Context.MODE_PRIVATE)
        val savedRepo = prefs.getString("target_repo", "GetyeTek/Notify")
        inputRepo.setText(savedRepo)
        switchAuto.isChecked = prefs.getBoolean("auto_update", false)

        adapter = BuildAdapter(emptyList()) { build -> handleDownload(build) }
        recycler.layoutManager = LinearLayoutManager(this)
        recycler.adapter = adapter

        fabRefresh.setOnClickListener { 
            saveRepo(inputRepo.text.toString())
            loadBuilds() 
        }

        btnMonitor.setOnClickListener {
             val repo = inputRepo.text.toString().trim()
             if (repo.isEmpty()) {
                 Toast.makeText(this, "Please enter a Repo", Toast.LENGTH_SHORT).show()
                 return@setOnClickListener
             }
             saveRepo(repo)

             val intent = Intent(this, MonitorService::class.java)
             if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) startForegroundService(intent) else startService(intent)

             statusText.text = "Service: Active ($repo)"
             statusText.setTextColor(0xFF4CAF50.toInt())
             Toast.makeText(this, "Monitoring Started", Toast.LENGTH_SHORT).show()
        }

        btnKill.setOnClickListener {
             LogManager.log("UI: Stopping service manually")
             val intent = Intent(this, MonitorService::class.java)
             stopService(intent)
             statusText.text = "Service: Killed"
             statusText.setTextColor(0xFFF44336.toInt())
             Toast.makeText(this, "Service Killed", Toast.LENGTH_SHORT).show()
        }

        btnLogs.setOnClickListener { showLogDialog() }

        switchAuto.setOnCheckedChangeListener { _, isChecked ->
            prefs.edit().putBoolean("auto_update", isChecked).apply()
        }

        btnPerm.setOnClickListener {
            if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
                val intent = Intent(android.provider.Settings.ACTION_MANAGE_UNKNOWN_APP_SOURCES)
                intent.data = Uri.parse("package:$packageName")
                startActivity(intent)
            } else {
                Toast.makeText(this, "Direct setting not available on this Android version", Toast.LENGTH_SHORT).show()
            }
        }

        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU) {
            requestPermissionLauncher.launch(Manifest.permission.POST_NOTIFICATIONS)
        }
        loadBuilds()
    }

    private fun saveRepo(repo: String) {
        val prefs = getSharedPreferences("BuildPrefs", Context.MODE_PRIVATE)
        prefs.edit().putString("target_repo", repo.ifEmpty { "GetyeTek/Notify" }).apply()
    }

    private fun getRepo(): String {
         val prefs = getSharedPreferences("BuildPrefs", Context.MODE_PRIVATE)
         return prefs.getString("target_repo", "GetyeTek/Notify") ?: "GetyeTek/Notify"
    }

    private fun loadBuilds() {
        val repo = getRepo()
        scope.launch(Dispatchers.IO) {
            val runs = ApiHelper.fetchRuns(repo)
            withContext(Dispatchers.Main) {
                if (runs.isEmpty()) Toast.makeText(this@MainActivity, "No builds found for $repo", Toast.LENGTH_SHORT).show()
                adapter.updateList(runs)
            }
        }
    }

    private fun handleDownload(build: BuildStatus) {
        Toast.makeText(this, "Fetching download link...", Toast.LENGTH_SHORT).show()
        val repo = getRepo()

        scope.launch(Dispatchers.IO) {
            val url = ApiHelper.fetchArtifactLink(repo, build.runId, build.branch)

            withContext(Dispatchers.Main) {
                if (url != null) {
                    startDownload(url, build.runNumber, build.conduitId)
                } else {
                    Toast.makeText(this@MainActivity, "No artifact found for this build", Toast.LENGTH_LONG).show()
                }
                adapter.notifyDataSetChanged()
            }
        }
    }

    private fun startDownload(url: String, runNumber: Int, tag: String?) {
        try {
            val repo = getRepo()
            val safeRepo = repo.replace("/", "_")
            val safeTag = tag ?: "NA"

            val request = DownloadManager.Request(Uri.parse(url))
                .setTitle("Manual Download: $repo #$runNumber")
                .setDescription("META|$repo|$runNumber|$safeTag")
                .setNotificationVisibility(DownloadManager.Request.VISIBILITY_VISIBLE_NOTIFY_COMPLETED)
                .setDestinationInExternalPublicDir(Environment.DIRECTORY_DOWNLOADS, "Notify/$safeRepo/build-$runNumber.zip")

            val dm = getSystemService(Context.DOWNLOAD_SERVICE) as DownloadManager
            dm.enqueue(request)
            Toast.makeText(this, "Download started...", Toast.LENGTH_SHORT).show()
        } catch (e: Exception) {
            Toast.makeText(this, "Failed to start download: ${e.message}", Toast.LENGTH_LONG).show()
        }
    }

    private fun showLogDialog() {
        val dialog = com.google.android.material.bottomsheet.BottomSheetDialog(this)
        val view = layoutInflater.inflate(R.layout.dialog_logs, null)
        val recycler = view.findViewById<androidx.recyclerview.widget.RecyclerView>(R.id.recycler_logs)

        val adapter = object : androidx.recyclerview.widget.RecyclerView.Adapter<androidx.recyclerview.widget.RecyclerView.ViewHolder>() {
            override fun onCreateViewHolder(p: android.view.ViewGroup, t: Int) = object : androidx.recyclerview.widget.RecyclerView.ViewHolder(android.widget.TextView(this@MainActivity).apply {
                setTextColor(0xFFAAAAAA.toInt())
                textSize = 12f
                setPadding(10, 10, 10, 10)
                layoutParams = android.view.ViewGroup.LayoutParams(-1, -2)
            }) {}
            override fun onBindViewHolder(h: androidx.recyclerview.widget.RecyclerView.ViewHolder, p: Int) { (h.itemView as android.widget.TextView).text = LogManager.logs[p] }
            override fun getItemCount() = LogManager.logs.size
        }

        recycler.layoutManager = androidx.recyclerview.widget.LinearLayoutManager(this)
        recycler.adapter = adapter

        view.findViewById<android.view.View>(R.id.btn_clear_logs).setOnClickListener { LogManager.clear(); adapter.notifyDataSetChanged() }
        view.findViewById<android.view.View>(R.id.btn_copy_logs).setOnClickListener { 
            val cb = getSystemService(android.content.Context.CLIPBOARD_SERVICE) as android.content.ClipboardManager
            cb.setPrimaryClip(android.content.ClipData.newPlainText("Logs", LogManager.getAllText()))
            Toast.makeText(this, "Copied to clipboard", Toast.LENGTH_SHORT).show()
        }
        view.findViewById<android.view.View>(R.id.btn_close_logs).setOnClickListener { dialog.dismiss() }

        dialog.setContentView(view)
        dialog.show()
    }

    override fun onDestroy() {
        super.onDestroy()
        scope.cancel()
    }
}

package com.getyetek.notify

import android.app.DownloadManager
import android.app.NotificationChannel
import android.app.NotificationManager
import android.app.Service
import android.content.BroadcastReceiver
import android.content.Context
import android.content.Intent
import android.content.IntentFilter
import android.net.Uri
import android.os.Build
import android.os.Environment
import android.os.IBinder
import android.widget.Toast
import androidx.core.app.NotificationCompat
import androidx.core.content.FileProvider
import kotlinx.coroutines.*
import java.io.File
import java.io.FileOutputStream
import java.util.zip.ZipInputStream

class MonitorService : Service() {

    private val serviceScope = CoroutineScope(Dispatchers.IO + Job())
    private var isMonitoring = false

    // AUTO-KILL LOGIC
    private var lastActivityTime = 0L
    private val TIMEOUT_MS = 30 * 60 * 1000 // 30 Minutes

    companion object {
        const val CHANNEL_ID = "build_monitor_channel"
        const val PREFS_NAME = "BuildPrefs"
        const val KEY_LAST_ID = "last_notified_id"
        const val KEY_REPO = "target_repo"
        const val KEY_AUTO_UPDATE = "auto_update"
        const val NOTIFICATION_ID_FOREGROUND = 1
    }

    override fun onBind(intent: Intent?): IBinder? = null

    override fun onStartCommand(intent: Intent?, flags: Int, startId: Int): Int {
        if (!isMonitoring) {
            createNotificationChannel()
            if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU) {
                registerReceiver(onDownloadComplete, IntentFilter(DownloadManager.ACTION_DOWNLOAD_COMPLETE), Context.RECEIVER_EXPORTED)
            } else {
                registerReceiver(onDownloadComplete, IntentFilter(DownloadManager.ACTION_DOWNLOAD_COMPLETE))
            }

            lastActivityTime = System.currentTimeMillis()

            val notification = NotificationCompat.Builder(this, CHANNEL_ID)
                .setContentTitle("Build Watcher Active")
                .setContentText("Auto-kill in 2h if idle")
                .setSmallIcon(android.R.drawable.ic_popup_sync)
                .build()

            startForeground(NOTIFICATION_ID_FOREGROUND, notification)
            isMonitoring = true
            startPolling()
        }
        return START_STICKY
    }

    private fun startPolling() {
        LogManager.log("SERVICE: Polling started")
        serviceScope.launch {
            while (isMonitoring) {
                // 1. CHECK TIMEOUT
                val timeSinceLastBuild = System.currentTimeMillis() - lastActivityTime
                if (timeSinceLastBuild > TIMEOUT_MS) {
                    notifyTimeout()
                    stopSelf() // Kill the service
                    break
                }

                // 2. POLL API
                try {
                    val prefs = getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)
                    val currentRepo = prefs.getString(KEY_REPO, "GetyeTek/Notify") ?: "GetyeTek/Notify"

                    val result = ApiHelper.fetchBuildStatus(currentRepo)
                    if (result != null) {
                        checkAndNotify(result)
                    } else {
                        LogManager.log("SERVICE: No builds found for $currentRepo")
                    }
                } catch (e: Exception) {
                    e.printStackTrace()
                }

                // 3. WAIT (30s)
                delay(30_000)
            }
        }
    }

    private fun checkAndNotify(build: BuildStatus) {
        val prefs = getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)
        val lastId = prefs.getLong(KEY_LAST_ID, -1)

        // If we found a NEW build that is COMPLETED
        if (build.runId > lastId && build.status == "completed") {
            LogManager.log("SERVICE: New completed build found: #${build.runNumber}")
            sendAlert(build)
            prefs.edit().putLong(KEY_LAST_ID, build.runId).apply()

            lastActivityTime = System.currentTimeMillis()
            updateNotificationText("Last build: #${build.runNumber} (Timer Reset)")

            // AUTO UPDATE LOGIC
            if (build.conclusion == "success" && prefs.getBoolean(KEY_AUTO_UPDATE, false)) {
                val repo = prefs.getString(KEY_REPO, "GetyeTek/Notify") ?: "GetyeTek/Notify"
                serviceScope.launch {
                    val url = ApiHelper.fetchArtifactLink(repo, build.runId, build.branch)
                    if (url != null) startAutoDownload(url, build.runNumber, build.conduitId)
                }
            }
        }
    }

    private fun updateNotificationText(text: String) {
        val notification = NotificationCompat.Builder(this, CHANNEL_ID)
            .setContentTitle("Build Watcher Active")
            .setContentText(text)
            .setSmallIcon(android.R.drawable.ic_popup_sync)
            .build()
        val manager = getSystemService(Context.NOTIFICATION_SERVICE) as NotificationManager
        manager.notify(NOTIFICATION_ID_FOREGROUND, notification)
    }

    private fun sendAlert(build: BuildStatus) {
        val isSuccess = build.conclusion == "success"
        val title = if (isSuccess) "Build Success!" else "Build Failed"
        val color = if (isSuccess) 0xFF4CAF50.toInt() else 0xFFF44336.toInt()
        val icon = if (isSuccess) android.R.drawable.stat_sys_download_done else android.R.drawable.stat_notify_error

        val notification = NotificationCompat.Builder(this, CHANNEL_ID)
            .setContentTitle(title)
            .setContentText("${build.name} #${build.runNumber}")
            .setSmallIcon(icon)
            .setColor(color)
            .setPriority(NotificationCompat.PRIORITY_MAX)
            .setDefaults(NotificationCompat.DEFAULT_ALL)
            .setAutoCancel(true)
            .build()

        val manager = getSystemService(Context.NOTIFICATION_SERVICE) as NotificationManager
        manager.notify(build.runId.toInt(), notification)
    }

    private fun notifyTimeout() {
        val notification = NotificationCompat.Builder(this, CHANNEL_ID)
            .setContentTitle("Monitoring Stopped")
            .setContentText("No new builds for 30m. Service killed to save battery.")
            .setSmallIcon(android.R.drawable.ic_menu_close_clear_cancel)
            .setAutoCancel(true)
            .build()
        val manager = getSystemService(Context.NOTIFICATION_SERVICE) as NotificationManager
        manager.notify(999, notification)
    }

    private fun startAutoDownload(url: String, runNumber: Int, tag: String?) {
        val prefs = getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)
        val repo = prefs.getString(KEY_REPO, "Unknown") ?: "Unknown"
        val safeRepo = repo.replace("/", "_")
        val safeTag = tag ?: "NA"

        val request = DownloadManager.Request(Uri.parse(url))
            .setTitle("Auto-Updating $repo #$runNumber")
            .setDescription("META|$repo|$runNumber|$safeTag")
            .setNotificationVisibility(DownloadManager.Request.VISIBILITY_VISIBLE)
            .setDestinationInExternalPublicDir(Environment.DIRECTORY_DOWNLOADS, "Notify/$safeRepo/build-$runNumber.zip")

        val dm = getSystemService(Context.DOWNLOAD_SERVICE) as DownloadManager
        dm.enqueue(request)
    }

    private val onDownloadComplete = object : BroadcastReceiver() {
        override fun onReceive(context: Context, intent: Intent) {
            val id = intent.getLongExtra(DownloadManager.EXTRA_DOWNLOAD_ID, -1)
            if (id == -1L) return

            val dm = context.getSystemService(Context.DOWNLOAD_SERVICE) as DownloadManager
            val query = DownloadManager.Query().setFilterById(id)
            val cursor = dm.query(query)
            if (cursor.moveToFirst()) {
                val status = cursor.getInt(cursor.getColumnIndex(DownloadManager.COLUMN_STATUS))
                val fileUriString = cursor.getString(cursor.getColumnIndex(DownloadManager.COLUMN_LOCAL_URI))
                val description = cursor.getString(cursor.getColumnIndex(DownloadManager.COLUMN_DESCRIPTION))
                cursor.close()

                if (status == DownloadManager.STATUS_SUCCESSFUL && fileUriString != null) {
                    if (description?.startsWith("META|") == true) {
                        val parts = description.split("|")
                        val repo = parts.getOrNull(1) ?: "Unknown"
                        val runNo = parts.getOrNull(2) ?: "0"
                        val tag = parts.getOrNull(3) ?: "NA"
                        processDownloadedZip(Uri.parse(fileUriString), repo, runNo, tag)
                    } else {
                        processDownloadedZip(Uri.parse(fileUriString), "Manual", "0", "NA")
                    }
                }
            }
        }
    }

    private fun processDownloadedZip(zipUri: Uri, repo: String, runNumber: String, tag: String) {
        val safeRepo = repo.replace("/", "_")
        val downloadFolder = Environment.getExternalStoragePublicDirectory(Environment.DIRECTORY_DOWNLOADS)
        val targetDir = File(downloadFolder, "Notify/$safeRepo")
        if (!targetDir.exists()) targetDir.mkdirs()

        val fileName = if (tag != "NA") "build-$runNumber-tag-$tag.apk" else "build-$runNumber.apk"
        val targetApk = File(targetDir, fileName)
        serviceScope.launch(Dispatchers.IO) {
            try {
                LogManager.log("UNZIP: Processing zip for build $runNumber")
                contentResolver.openInputStream(zipUri)?.use { input ->
                    ZipInputStream(input).use { zis ->
                        var entry = zis.nextEntry
                        while (entry != null) {
                            if (entry.name.endsWith(".apk")) {
                                FileOutputStream(targetApk).use { fos -> zis.copyTo(fos) }
                                break
                            }
                            zis.closeEntry()
                            entry = zis.nextEntry
                        }
                    }
                }

                if (targetApk.exists()) {
                    LogManager.log("UNZIP SUCCESS: APK extracted to ${targetApk.name}")
                    triggerInstallation(targetApk)
                    // Cleanup the zip file
                    val zipFile = File(zipUri.path ?: "")
                    if (zipFile.exists()) zipFile.delete()
                }
            } catch (e: Exception) { e.printStackTrace() }
        }
    }

    private fun triggerInstallation(file: File) {
        LogManager.log("INSTALL: Firing intent for ${file.name}")
        val apkUri = FileProvider.getUriForFile(this, "com.getyetek.notify.fileprovider", file)
        val installIntent = Intent(Intent.ACTION_VIEW).apply {
            setDataAndType(apkUri, "application/vnd.android.package-archive")
            addFlags(Intent.FLAG_GRANT_READ_URI_PERMISSION)
            addFlags(Intent.FLAG_ACTIVITY_NEW_TASK)
        }
        startActivity(installIntent)
    }

    private fun createNotificationChannel() {
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
            val channel = NotificationChannel(
                CHANNEL_ID,
                "Build Notifications",
                NotificationManager.IMPORTANCE_HIGH
            )
            val manager = getSystemService(Context.NOTIFICATION_SERVICE) as NotificationManager
            manager.createNotificationChannel(channel)
        }
    }

    override fun onDestroy() {
        super.onDestroy()
        isMonitoring = false
        try { unregisterReceiver(onDownloadComplete) } catch (e: Exception) {}
        serviceScope.cancel()
    }
}

